// Each element flows through filter → map → sorted → distinct → collector.
// If people is 10 million items but only 100 are 18+, no wasted work.

// File: StreamsDemo.java
// Compile: javac StreamsDemo.java && java StreamsDemo
import java.util.*;
import java.util.stream.*;
import static java.util.stream.Collectors.*;

record Person(String name, String dept, int salary) { }

public class StreamsDemo {
  public static void main(String[] args) {
    List<Person> people = List.of(
      new Person("Ada",  "eng",     900_000),
      new Person("Bob",  "eng",     800_000),
      new Person("Kim",  "design",  700_000),
      new Person("Zoe",  "eng",   1_100_000),
      new Person("Sam",  "design",  650_000),
      new Person("Ivan", "pm",      950_000));

    // --- Basic filter/map/collect ---
    List<String> engineers = people.stream()
        .filter(p -> p.dept().equals("eng"))
        .map(Person::name)
        .sorted()
        .toList();                              // Java 16+: toList() shorthand
    System.out.println("engineers      : " + engineers);

    // --- Aggregation: total salary ---
    long total = people.stream()
        .mapToInt(Person::salary)
        .sum();
    System.out.println("total salary   : " + total);

    // --- Grouping by department ---
    Map<String, List<String>> byDept = people.stream()
        .collect(groupingBy(Person::dept, mapping(Person::name, toList())));
    System.out.println("by dept        : " + byDept);

    // --- Count per department ---
    Map<String, Long> countByDept = people.stream()
        .collect(groupingBy(Person::dept, counting()));
    System.out.println("count by dept  : " + countByDept);

    // --- Average salary per department ---
    Map<String, Double> avgSalary = people.stream()
        .collect(groupingBy(Person::dept, averagingInt(Person::salary)));
    System.out.println("avg by dept    : " + avgSalary);

    // --- Split into 'high paid' and 'other' ---
    Map<Boolean, List<String>> split = people.stream()
        .collect(partitioningBy(p -> p.salary() > 800_000,
                                mapping(Person::name, toList())));
    System.out.println("high paid?     : " + split);

    // --- Short-circuit — find first engineer > 900k ---
    Optional<Person> found = people.stream()
        .filter(p -> p.dept().equals("eng") && p.salary() > 900_000)
        .findFirst();
    System.out.println("first hit      : " + found.orElse(null));

    // --- Joined names ---
    String allNames = people.stream()
        .map(Person::name)
        .collect(joining(", "));
    System.out.println("names          : " + allNames);

    // --- LAZY proof: infinite stream, but we only need 5 ---
    List<Integer> squares = Stream.iterate(1, i -> i + 1)
        .map(i -> i * i)
        .limit(5)
        .toList();
    System.out.println("first 5 sq     : " + squares);

    // --- Parallel — same code, faster on big data (if it fits the criteria) ---
    long count = IntStream.rangeClosed(1, 10_000_000)
        .parallel()
        .filter(n -> n % 7 == 0)
        .count();
    System.out.println("parallel count : " + count);
  }
}

// Expected output:
//   engineers      : [Ada, Bob, Zoe]
//   total salary   : 5100000
//   by dept        : {design=[Kim, Sam], eng=[Ada, Bob, Zoe], pm=[Ivan]}
//   count by dept  : {design=2, eng=3, pm=1}
//   avg by dept    : {design=675000.0, eng=933333.3333, pm=950000.0}
//   high paid?     : {false=[Bob, Kim, Sam], true=[Ada, Zoe, Ivan]}
//   first hit      : Person[name=Zoe, ...]
//   names          : Ada, Bob, Kim, Zoe, Sam, Ivan
//   first 5 sq     : [1, 4, 9, 16, 25]
//   parallel count : 1428571
